SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, CHR(34) || EXISTS(SELECT FROM information_schema.tables WHERE table_schema = 'aws_oracle_ext' AND TABLE_NAME = 'versions') || CHR(34) AS sct_oracle_extension_exists